import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

const categoryColors = {
  Languages: "var(--accent)",
  Frameworks: "var(--accent2)",
  Tools: "var(--accent3)",
  Databases: "#34d399",
  Concepts: "#f472b6",
};

export function SectionLabel({ text }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4 }}
      viewport={{ once: true }}
      style={{ display:"inline-flex", alignItems:"center", gap:8, marginBottom:"0.75rem" }}
    >
      <span style={{ width:22, height:1, background:"var(--accent)" }} />
      <span style={{
        fontSize:"0.7rem",
        color:"var(--accent)",
        fontFamily:"var(--font-display)",
        fontWeight:700,
        letterSpacing:"0.12em",
        textTransform:"uppercase"
      }}>
        {text}
      </span>
    </motion.div>
  );
}

export const sectionTitle = {
  fontFamily: "var(--font-display)",
  fontWeight: 800,
  fontSize: "clamp(1.6rem, 3.5vw, 2.5rem)",
  letterSpacing: "-0.02em",
  marginBottom: "1.75rem",
  lineHeight: 1.1,
};

export default function Skills({ skills }) {
  const [active, setActive] = useState("Languages");
  const categories = Object.keys(skills);

  return (
    <>
      <style>{`
        .skills-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
          max-width: 1200px;
          margin: auto;
        }

        .skill-tabs {
          display: flex;
          gap: 0.5rem;
          flex-wrap: wrap;
          margin-bottom: 1.5rem;
        }

        .skill-tab {
          padding: 7px 16px;
          border-radius: 99px;
          border: 1px solid;
          font-family: var(--font-display);
          font-weight: 600;
          font-size: clamp(0.72rem, 1.1vw, 0.85rem);
          cursor: pointer;
          transition: all 0.25s ease;
          white-space: nowrap;
        }

        .skill-tab:hover {
          transform: translateY(-2px);
        }

        .skill-chips {
          display: flex;
          flex-wrap: wrap;
          gap: 0.65rem;
        }

        .skill-chip {
          background: var(--surface2);
          border-radius: 8px;
          padding: 9px 15px;
          font-weight: 500;
          font-size: clamp(0.78rem, 1.3vw, 0.9rem);
          color: var(--text);
          transition: all 0.25s ease;
          cursor: default;
        }

        @media (max-width: 768px) {
          .skill-chips {
            justify-content: center;
          }
        }

        @media (max-width: 480px) {
          .skill-tab { font-size: 0.72rem; padding: 6px 12px; }
          .skill-chip { font-size: 0.8rem; padding: 8px 12px; }
        }
      `}</style>

      <section className="skills-section" id="skills">
        <SectionLabel text="Expertise" />

        <motion.h2
          style={sectionTitle}
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          viewport={{ once: true }}
        >
          Technical Skills
        </motion.h2>

        {/* Tabs */}
        <div className="skill-tabs">
          {categories.map(cat => (
            <motion.button
              key={cat}
              className="skill-tab"
              onClick={() => setActive(cat)}
              whileTap={{ scale: 0.95 }}
              animate={{
                borderColor: active === cat ? categoryColors[cat] : "var(--border)",
                background: active === cat ? `${categoryColors[cat]}18` : "transparent",
                color: active === cat ? categoryColors[cat] : "var(--muted)",
              }}
              transition={{ duration: 0.25 }}
            >
              {cat}
            </motion.button>
          ))}
        </div>

        {/* Skills */}
        <motion.div layout className="skill-chips">
          <AnimatePresence mode="wait">
            {skills[active].map((skill, i) => (
              <motion.div
                key={skill}
                className="skill-chip"
                initial={{ opacity: 0, y: 15, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{
                  delay: i * 0.05,
                  duration: 0.3,
                }}
                style={{
                  border: `1px solid ${categoryColors[active]}30`,
                }}
                whileHover={{
                  y: -4,
                  scale: 1.05,
                }}
                onMouseEnter={e => {
                  e.currentTarget.style.borderColor = categoryColors[active];
                  e.currentTarget.style.background = `${categoryColors[active]}10`;
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.borderColor = `${categoryColors[active]}30`;
                  e.currentTarget.style.background = "var(--surface2)";
                }}
              >
                <span style={{
                  color: categoryColors[active],
                  marginRight: 6,
                  fontSize: "0.65rem"
                }}>
                  ▸
                </span>
                {skill}
              </motion.div>
            ))}
          </AnimatePresence>
        </motion.div>
      </section>
    </>
  );
}
